public class CssParser_parse_1_Test {

  /**
   * Scenario TC09: handleRuleSet throws PrematureEOFException → suppressed, parser breaks loop and calls endDocument
   */
  @Test
  @DisplayName("handleRuleSet throws PrematureEOFException → suppressed, parser breaks loop and calls endDocument")
  public void test_TC09() throws Exception {
    // Prepare a spy parser
    CssParser parser = spy(new CssParser(Locale.ENGLISH));
    // Mock error & doc handlers
    CssErrorHandler err = mock(CssErrorHandler.class);
    CssContentHandler doc = mock(CssContentHandler.class);

    // Create a dummy iterator that has one IDENT token and then no more
    CssTokenIterator singleIdentIter = mock(CssTokenIterator.class);
    when(singleIdentIter.hasNext(any())).thenReturn(true, false);
    CssToken ident = new CssToken(CssToken.Type.IDENT, "foo", new Location(1,1));
    when(singleIdentIter.next(any())).thenReturn(ident);

    // Stub private scan() to return our iterator
    Method scan = CssParser.class.getDeclaredMethod("scan", Reader.class, String.class, CssErrorHandler.class);
    scan.setAccessible(true);
    doReturn(singleIdentIter).when(parser).scan(any(Reader.class), anyString(), any(CssErrorHandler.class)); // Changed to match Mockito's when method

    // Stub private handleRuleSet to throw PrematureEOFException
    Method handleRuleSet = CssParser.class.getDeclaredMethod("handleRuleSet", 
        CssToken.class, CssTokenIterator.class, CssContentHandler.class, CssErrorHandler.class);
    handleRuleSet.setAccessible(true);
    doThrow(new PrematureEOFException()).when(parser).handleRuleSet(any(), any(), any(), any()); // Changed to match Mockito's when method

    // Run parse: should not throw, and startDocument/endDocument called once
    parser.parse(new StringReader(""), "sys", err, doc);

    verify(doc, times(1)).startDocument();
    verify(doc, times(1)).endDocument();
  }

  /**
   * Scenario TC10: Three tokens [IDENT, ATKEYWORD, IDENT] → handleRuleSet, handleAtRule, handleRuleSet called in order
   */
  @Test
  @DisplayName("Three tokens [IDENT, ATKEYWORD, IDENT] → handleRuleSet, handleAtRule, handleRuleSet called in order")
  public void test_TC10() throws Exception {
    CssParser parser = spy(new CssParser(Locale.ENGLISH));
    CssErrorHandler err = mock(CssErrorHandler.class);
    CssContentHandler doc = mock(CssContentHandler.class);

    // Create three tokens: IDENT, ATKEYWORD, IDENT
    CssToken t1 = new CssToken(CssToken.Type.IDENT, "id", new Location(1,1));
    CssToken t2 = new CssToken(CssToken.Type.ATKEYWORD, "@a", new Location(1,2));
    CssToken t3 = new CssToken(CssToken.Type.IDENT, "id2", new Location(1,3));

    // Iterator stub
    CssTokenIterator mixIter = mock(CssTokenIterator.class);
    // hasNext with FILTER_S_CMNT_CDO_CDC: true three times then false
    when(mixIter.hasNext(any())).thenReturn(true, true, true, false);
    // next returns t1,t2,t3
    when(mixIter.next(any())).thenReturn(t1, t2, t3);

    // Stub scan
    Method scan = CssParser.class.getDeclaredMethod("scan", Reader.class, String.class, CssErrorHandler.class);
    scan.setAccessible(true);
    doReturn(mixIter).when(parser).scan(any(Reader.class), anyString(), any(CssErrorHandler.class)); // Changed to match Mockito's when method

    // Stub handlers to do nothing
    Method handleRuleSet = CssParser.class.getDeclaredMethod("handleRuleSet", 
        CssToken.class, CssTokenIterator.class, CssContentHandler.class, CssErrorHandler.class);
    handleRuleSet.setAccessible(true);
    doNothing().when(parser).handleRuleSet(any(), any(), any(), any()); // Changed to match Mockito's when method

    Method handleAtRule = CssParser.class.getDeclaredMethod("handleAtRule", 
        CssToken.class, CssTokenIterator.class, CssContentHandler.class, CssErrorHandler.class);
    handleAtRule.setAccessible(true);
    doNothing().when(parser).handleAtRule(any(), any(), any(), any()); // Changed to match Mockito's when method

    // Execute
    parser.parse(new StringReader(""), "sys", err, doc);

    // Verify calls in counts
    // First and third tokens are IDENT → handleRuleSet twice
    verify(parser, times(2)).invoke(handleRuleSet, t1, mixIter, doc, err);
    // Second token is ATKEYWORD → handleAtRule once
    verify(parser, times(1)).invoke(handleAtRule, t2, mixIter, doc, err);
    verify(doc, times(1)).endDocument();
  }

  /**
   * Scenario TC11: handleAtRule throws generic CssException → propagate to caller
   */
  @Test
  @DisplayName("handleAtRule throws generic CssException → propagate to caller")
  public void test_TC11() throws Exception {
    CssParser parser = spy(new CssParser(Locale.ENGLISH));
    CssErrorHandler err = mock(CssErrorHandler.class);
    CssContentHandler doc = mock(CssContentHandler.class);

    // Single ATKEYWORD token iterator
    CssTokenIterator atIter = mock(CssTokenIterator.class);
    when(atIter.hasNext(any())).thenReturn(true, false);
    CssToken at = new CssToken(CssToken.Type.ATKEYWORD, "@x", new Location(1,1));
    when(atIter.next(any())).thenReturn(at);

    // Stub scan
    Method scan = CssParser.class.getDeclaredMethod("scan", Reader.class, String.class, CssErrorHandler.class);
    scan.setAccessible(true);
    doReturn(atIter).when(parser).scan(any(Reader.class), anyString(), any(CssErrorHandler.class)); // Changed to match Mockito's when method

    // Stub handleAtRule to throw CssException
    CssException cssEx = new ConcreteCssException(CssErrorCode.GRAMMAR_UNEXPECTED_TOKEN, at.location, Locale.ENGLISH, "err"); // Changed to use a concrete subclass
    Method handleAtRule = CssParser.class.getDeclaredMethod("handleAtRule", 
        CssToken.class, CssTokenIterator.class, CssContentHandler.class, CssErrorHandler.class);
    handleAtRule.setAccessible(true);
    doThrow(cssEx).when(parser).handleAtRule(any(), any(), any(), any()); // Changed to match Mockito's when method

    // Expect propagate CssException
    assertThrows(CssException.class,
        () -> parser.parse(new StringReader(""), "sys", err, doc));
  }

  /**
   * Scenario TC12: scan throws RuntimeException → propagate unchecked exception
   */
  @Test
  @DisplayName("scan throws RuntimeException → propagate unchecked exception")
  public void test_TC12() throws Exception {
    CssParser parser = spy(new CssParser(Locale.ENGLISH));
    // Stub scan to throw IllegalStateException
    Method scan = CssParser.class.getDeclaredMethod("scan", Reader.class, String.class, CssErrorHandler.class);
    scan.setAccessible(true);
    doThrow(new IllegalStateException("boom"))
        .when(parser).scan(any(Reader.class), anyString(), any(CssErrorHandler.class)); // Changed to match Mockito's when method

    // Expect unchecked exception propagated
    assertThrows(IllegalStateException.class,
        () -> parser.parse(new StringReader(""), "sys",
            mock(CssErrorHandler.class), mock(CssContentHandler.class)));
  }
